		"run_id", run.ID,
		"semantic_release_id", sr.ID,
		"version", sr.Version,
	)

	return &agentResult{
		semanticReleaseID: sr.ID,
		version:           version,
		reportText:        finalText,
		projectName:       project.Name,
	}, nil
}

